            background-color: #fdfaf5 !important; /* 直接使用硬编码的颜色并设为最高优先级 */
            background-image: none !important; /* 强制清除任何可能继承的背景图 */
            opacity: 1 !important; /* 强制元素为完全不透明 */
            padding: 20px;
            border-radius: var(--radius-base);
            border: 1px solid var(--border-color);
            box-shadow: 0 5px 15px var(--shadow-color);
            width: 80%;
            max-width: 320px;
            position: relative;
            color: var(--text-main);
            font-size: 16px;
        }

        .simple-modal-header {
            font-family: var(--font-title);
            font-size: 1.2rem;
            font-weight: 700;
            color: var(--text-title);
            margin-bottom: 15px;
            padding-bottom: 10px;
            border-bottom: 1px solid var(--border-color);
        }

        .simple-modal-body {
            line-height: 1.7;
            margin-bottom: 20px;
            max-height: 200px;
            overflow-y: auto;
        }

        .simple-modal-close-btn {
            position: absolute;
            top: 10px;
            right: 10px;
            background: none;
            border: none;
            font-size: 24px;
            color: var(--accent-color1);
            cursor: pointer;
            transition: all 0.2s ease;
        }

        .simple-modal-close-btn:hover {
            color: var(--accent-color2);
            transform: scale(1.1);
        }

        @media (max-width: 600px) {
            body { padding: 5px; }
            .main-interface { padding: 10px; }
            .main-header h2 { font-size: 1.5rem; }
            .phone-interface {
                width: 100%;
                height: 100vh;
                border-radius: 0;
                border: none;
            }
        }
    </style>
</head>
<body>
    <div class="page-container">
        <div class="main-interface" id="main-page" style="background: #fdfaf5 !important; font-family: 'Quicksand', 'Noto Serif SC', serif !important; color: #5a3e2b !important; font-size: 17px !important; line-height: 1.6 !important;">
            <div class="main-header">
                <h2 id="main-title">Thời gian không xác định</h2>
                <div class="header-info" style="position: relative;">
                    <button class="phone-toggle-btn" onclick="showPhone()">
                        <i class="fas fa-mobile-alt"></i>
                    </button>
                    <span class="notification-dot" id="phone-notification-dot"></span>
                </div>
            </div>

            <div class="story-content-wrapper">
                <div class="story-content"><p>$1</p></div>
                <div class="player-choices">
                    <div class="choice-header">Lúc này, tôi quyết định...</div>
                    </div>
            </div>
        </div>

        <div class="phone-interface" id="phone-page">
            <div class="phone-screen">
        <div class="phone-status-bar">
            <div class="phone-status-left">
                <i class="fas fa-signal"></i>
                <i class="fas fa-wifi"></i>
            </div>
            <div id="phone-current-time">12:34</div>
            <div class="phone-status-right">
                <i class="fas fa-location-arrow"></i>
                <i class="fas fa-battery-three-quarters"></i>
            </div>
        </div>

            <div class="phone-app-container">
                <div class="phone-content active" id="messages-app">
                    <div class="phone-header">
                        <div class="phone-title">Tin nhắn</div>
                    </div>
                    <ul class="conversation-list" id="conversation-list">
                        </ul>
                </div>

                <div class="message-detail" id="message-detail">
                    <div class="message-header">
                        <button class="message-back-btn" onclick="showConversationList()">
                            <i class="fas fa-chevron-left"></i>
                        </button>
                        <div class="message-contact-name" id="message-contact-name">Người liên hệ</div>
                    </div>
                    <div class="message-list" id="message-list">
                        </div>
                </div>

                <div class="phone-content" id="moments-app">
                    <div class="phone-header">
                        <div class="phone-title">Động thái</div>
                    </div>
                    <div class="moments-list" id="moments-list">
                        </div>
                </div>

                <div class="phone-content" id="forum-app">
                    <div class="phone-header">
                        <div class="phone-title">Diễn đàn</div>
                    </div>
                    <div class="moments-list" id="forum-list">
                        </div>
                </div>
            </div>

            <div class="phone-tabs">
                    <div class="phone-tab active" onclick="switchTab('messages')">
                        <i class="fas fa-comments"></i>
                        <span>Tin nhắn</span>
                    </div>
                    <div class="phone-tab" onclick="switchTab('moments')">
                        <i class="fas fa-newspaper"></i>
                        <span>Động thái</span>
                    </div>
                    <div class="phone-tab" onclick="switchTab('forum')">
                        <i class="fas fa-bullhorn"></i>
                        <span>Diễn đàn</span>
                    </div>
                    <div class="phone-tab" onclick="showMainPage()">
                        <i class="fas fa-home"></i>
                        <span>Trở về</span>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <div class="simple-modal-overlay" id="simple-modal-overlay">
        <div class="simple-modal">
            <button class="simple-modal-close-btn" onclick="closeMediaViewer()">&times;</button>
            <div class="simple-modal-header" id="simple-modal-title">Chi tiết hình ảnh</div>
            <div class="simple-modal-body" id="simple-modal-text"></div>
        </div>
    </div>

    <script>
        // 全局页面切换函数
        function showMainPage() {
            document.getElementById('main-page').style.display = 'block';
            document.getElementById('phone-page').style.display = 'none';
        }

        function showPhone() {
            document.getElementById('main-page').style.display = 'none';
            document.getElementById('phone-page').style.display = 'block';

            // 点击后隐藏红点并记录状态
            localStorage.setItem('phoneNotificationSeen', 'true');
            if (typeof updatePhoneNotificationDot === 'function') {
                updatePhoneNotificationDot();
            }

            // 这些函数将在DOM加载后可用
            if (typeof updateTimeFromNewSource === 'function') {
                updateTimeFromNewSource(); // 从新端口更新时间
            }
            if (typeof loadPhoneData === 'function') {
                loadPhoneData(); // 从旧端口更新其他手机数据
            }
        }

        function openMediaViewer(text) {
            document.getElementById('simple-modal-text').textContent = text;
            document.getElementById('simple-modal-overlay').style.display = 'flex';
        }

        function closeMediaViewer() {
            document.getElementById('simple-modal-overlay').style.display = 'none';
        }

        function handleMomentInteractions(container) {
            container.querySelectorAll('.moment-item').forEach(item => {
                const likeBtn = item.querySelector('.like-action');
                const commentBtn = item.querySelector('.comment-action');
                const commentsSection = item.querySelector('.moment-comments-section');

                if (likeBtn) {
                    likeBtn.addEventListener('click', () => {
                        const postId = item.dataset.choiceIdentifier;
                        const isLiked = likeBtn.classList.toggle('liked');
                        const icon = likeBtn.querySelector('i');
                        icon.classList.toggle('far');
                        icon.classList.toggle('fas');

                        // 更新点赞数
                        const likeText = likeBtn.textContent || likeBtn.innerText;
                        const currentLikes = parseInt(likeText.match(/\d+/)?.[0] || 0);
                        const newLikes = isLiked ? currentLikes + 1 : currentLikes - 1;

                        likeBtn.innerHTML = `<i class="${isLiked ? 'fas' : 'far'} fa-heart"></i> Thích ${newLikes}`;

                        // 添加点赞动画效果
                        if (isLiked) {
                            likeBtn.style.color = 'var(--phone-notification)';
                            likeBtn.querySelector('i').style.color = 'var(--phone-notification)';
                            userLikes[postId] = true;
                        } else {
                            likeBtn.style.color = '';
                            likeBtn.querySelector('i').style.color = '';
                            delete userLikes[postId];
                        }
                        localStorage.setItem('userLikes', JSON.stringify(userLikes)); // 保存点赞状态
                    });
                }

                if (commentBtn) {
                    commentBtn.addEventListener('click', () => {
                        // Toggle display of the comments section
                        const isHidden = commentsSection.style.display === 'none';
                        commentsSection.style.display = isHidden ? 'block' : 'none';
                    });
                }

                // Add click listener for media item
                item.querySelectorAll('.moment-media-item').forEach(mediaItem => {
                    mediaItem.addEventListener('click', () => {
                        const description = mediaItem.dataset.description; // Read full description from data attribute
                        openMediaViewer(description);
                    });
                });
            });
        }

        document.addEventListener('DOMContentLoaded', function() {
            var dataSourceAPI = parent.Database2NumberAPI; // 旧插件API端口 (用于手机其他数据)
            var newDataSourceAPI = parent.AutoCardUpdaterAPI; // 新插件API端口 (仅用于时间)
            var currentConversationId = null;
            var isDataTimeAvailable = false; // 全局标志，判断是否应使用数据时间
            var userChoices = JSON.parse(localStorage.getItem('userChoices')) || {}; // 更新：从localStorage加载用户选择
            var userLikes = JSON.parse(localStorage.getItem('userLikes')) || {}; // 新增：从localStorage加载用户点赞记录
            var unreadConversations = JSON.parse(localStorage.getItem('unreadConversations')) || {}; // 新增: 用于跟踪会话的未读状态
            var lastMessageHashes = JSON.parse(localStorage.getItem('lastMessageHashes')) || {}; // 新增: 存储每个会话的最后一条消息哈希

            // 简单的字符串哈希函数
            function simpleHash(str) {
                let hash = 0;
                for (let i = 0; i < str.length; i++) {
                    const char = str.charCodeAt(i);
                    hash = (hash << 5) - hash + char;
                    hash |= 0; // Convert to 32bit integer
                }
                return hash;
            }

            // --- 通知红点逻辑 ---
            window.updatePhoneNotificationDot = function() {
                const dot = document.getElementById('phone-notification-dot');
                if (!dot) return;
                const seen = localStorage.getItem('phoneNotificationSeen');
                // 如果是 'false'，则显示红点，否则隐藏 (包括 null/undefined 的情况)
                if (seen === 'false') {
                    dot.style.display = 'block';
                } else {
                    dot.style.display = 'none';
                }
            }
            // --------------------

            // 更新手机时间 - 作为备用方案
            function updatePhoneTimeWithLocal() {
                // 仅在没有数据源时间时才使用本地系统时间
                if (!isDataTimeAvailable) {
                    var now = new Date();
                    var hours = now.getHours().toString().padStart(2, '0');
                    var minutes = now.getMinutes().toString().padStart(2, '0');
                    document.getElementById('phone-current-time').textContent = hours + ':' + minutes;
                }
            };

            // 新增：专门从新插件端口更新时间的函数
            function updateTimeFromNewSource() {
                try {
                    let timeString = '';
                    let timeUpdatedFromData = false;

                    if (newDataSourceAPI && typeof newDataSourceAPI.exportTableAsJson === 'function') {
                        const data = newDataSourceAPI.exportTableAsJson();
                        var tablesByName = {};
                        if (data && typeof data === 'object') {
                            for (var sheetId in data) {
                                if (Object.prototype.hasOwnProperty.call(data, sheetId) && data[sheetId] && data[sheetId].name) {
                                    tablesByName[data[sheetId].name] = {
                                        headers: data[sheetId].content[0] || [],
                                        rows: data[sheetId].content.slice(1)
                                    };
                                }
                            }
                        }

                        const globalDataTable = tablesByName["全局数据表"];
                        if (globalDataTable && globalDataTable.rows.length > 0) {
                            const headers = globalDataTable.headers;
                            const timeIndex = headers.indexOf("当前时间");
                            if (timeIndex !== -1) {
                                timeString = globalDataTable.rows[0][timeIndex] || '';
                            }
                        }
                    }

                    document.getElementById('main-title').textContent = timeString || 'Thời gian không xác định';

                    if (timeString) {
                        document.getElementById('phone-current-time').textContent = timeString;
                        timeUpdatedFromData = true;
                    }

                    isDataTimeAvailable = timeUpdatedFromData;
                    if (!isDataTimeAvailable) {
                        updatePhoneTimeWithLocal();
                    }
                } catch (e) {
                    console.error("Error getting time from new DataSource API:", e);
                    document.getElementById('main-title').textContent = 'Thời gian không xác định';
                    isDataTimeAvailable = false;
                    updatePhoneTimeWithLocal();
                }
            }

            window.switchTab = function(tabName) {
                // 更新Tab激活状态
                document.querySelectorAll('.phone-tab').forEach(tab => tab.classList.remove('active'));
                event.currentTarget.classList.add('active');

                // 切换内容页面
                document.querySelectorAll('.phone-content').forEach(content => content.classList.remove('active'));

                const activeContent = document.getElementById(tabName + '-app');
                if (activeContent) {
                    activeContent.classList.add('active');
                }

                // 确保消息详情页在切换Tab时总是隐藏的
                document.getElementById('message-detail').style.display = 'none';
                document.getElementById('messages-app').style.display = ''; // 确保消息列表容器可见
            }

            window.showConversationList = function() {
                document.getElementById('message-detail').style.display = 'none';
                // 当返回列表时，确保消息应用的主容器是可见的
                document.getElementById('messages-app').style.display = 'flex'; 
                // 重新加载会话列表以更新红点状态
                if (typeof loadPhoneData === 'function') {
                    // 只重新加载对话，避免刷新整个手机的数据
                     var data = getTableData();
                    var tablesByName = {};
                    if (data && typeof data === 'object') {
                        for (var sheetId in data) {
                            if (Object.prototype.hasOwnProperty.call(data, sheetId) && data[sheetId] && data[sheetId].name) {
                                tablesByName[data[sheetId].name] = {
                                    headers: data[sheetId].content[0] || [],
                                    rows: data[sheetId].content.slice(1)
                                };
                            }
                        }
                    }
                    loadConversations(tablesByName);
                }
            }

            function showMessageDetail(conversationId, contactName) {
                // 仅隐藏消息列表，而不是整个应用容器
                document.getElementById('messages-app').style.display = 'none'; 

                const messageDetail = document.getElementById('message-detail');
                messageDetail.style.display = 'flex';
                document.getElementById('message-contact-name').textContent = contactName;
                currentConversationId = conversationId;

                // 标记为已读并保存
                if (unreadConversations[conversationId]) {
                    delete unreadConversations[conversationId];
                    localStorage.setItem('unreadConversations', JSON.stringify(unreadConversations));
                }

                loadMessages(conversationId);
            }

            // 数据加载函数 - 只读取手机相关表格
            function getTableData() {
                try {
                    if (dataSourceAPI && typeof dataSourceAPI.exportTableAsJson === 'function') {
                        return dataSourceAPI.exportTableAsJson();
                    } else {
                        console.error("DataSource API (parent.Database2NumberAPI) not found or is invalid.");
                        return {};
                    }
                } catch (e) {
                    console.error("Error getting table data from DataSource API:", e);
                    return {};
                }
            }

            window.loadPhoneData = function() {
                var data = getTableData();
                var tablesByName = {};

                if (data && typeof data === 'object') {
                    for (var sheetId in data) {
                        if (Object.prototype.hasOwnProperty.call(data, sheetId) && data[sheetId] && data[sheetId].name) {
                            tablesByName[data[sheetId].name] = {
                                headers: data[sheetId].content[0] || [],
                                rows: data[sheetId].content.slice(1)
                            };
                        }
                    }
                }

                // 时间更新逻辑已移至独立的 updateTimeFromNewSource 函数

                loadConversations(tablesByName);
                loadMoments(tablesByName);
                loadForum(tablesByName);
            };

            function loadConversations(tablesByName) {
                var conversationList = document.getElementById('conversation-list');
                conversationList.innerHTML = '';

                const messageTable = tablesByName["消息记录表"];

                if (!messageTable || !messageTable.rows.length) {
                    conversationList.innerHTML = '<div style="text-align: center; color: var(--phone-secondary); padding: 40px;">Chưa có tin nhắn</div>';
                    return;
                }

                const headers = messageTable.headers;
                const sessionIdIndex = headers.indexOf("会话ID");
                const contentIndex = headers.indexOf("消息内容");
                const timeIndex = headers.indexOf("消息发送时间");

                const conversations = {};
                messageTable.rows.forEach(row => {
                    const conversationId = row[sessionIdIndex];
                    if (conversationId) {
                        conversations[conversationId] = {
                            lastMessage: row[contentIndex] || '...',
                            lastTime: row[timeIndex] || ''
                        };
                    }
                });

                // 分离未读和已读会话，然后各自排序
                const unreadIds = [];
                const readIds = [];

                Object.keys(conversations).forEach(id => {
                    if (unreadConversations[id]) {
                        unreadIds.push(id);
                    } else {
                        readIds.push(id);
                    }
                });

                const sortFn = (a, b) => (new Date(conversations[b].lastTime).getTime() || 0) - (new Date(conversations[a].lastTime).getTime() || 0);

                unreadIds.sort(sortFn);
                readIds.sort(sortFn);

                const sortedConversationIds = [...unreadIds, ...readIds];

                sortedConversationIds.forEach(conversationId => {
                    const convData = conversations[conversationId];

                    var conversationItem = document.createElement('li');
                    conversationItem.className = 'conversation-item';
                    conversationItem.onclick = () => showMessageDetail(conversationId, conversationId);

                    var avatar = document.createElement('div');
                    avatar.className = 'conversation-avatar';
                    avatar.innerHTML = '<i class="fas fa-user"></i>';

                    // 如果是未读，在头像上加个小红点
                    if (unreadConversations[conversationId]) {
                        var unreadDot = document.createElement('span');
                        unreadDot.className = 'notification-dot';
                        unreadDot.style.display = 'block';
                        unreadDot.style.top = '0px';
                        unreadDot.style.right = '0px';
                        unreadDot.style.borderWidth = '1px';
                        avatar.appendChild(unreadDot);
                    }

                    conversationItem.appendChild(avatar);

                    var info = document.createElement('div');
                    info.className = 'conversation-info';

                    var name = document.createElement('div');
                    name.className = 'conversation-name';
                    name.textContent = conversationId;
                    info.appendChild(name);

                    var lastMsg = document.createElement('div');
                    lastMsg.className = 'conversation-last-message';
                    lastMsg.textContent = convData.lastMessage;
                    info.appendChild(lastMsg);

                    conversationItem.appendChild(info);

                    var meta = document.createElement('div');
                    meta.className = 'conversation-meta';

                    var time = document.createElement('div');
                    time.className = 'conversation-time';
                    time.textContent = formatTime(convData.lastTime) || 'Vừa xong';
                    meta.appendChild(time);

                    conversationItem.appendChild(meta);
                    conversationList.appendChild(conversationItem);
                });
            }

            function loadMessages(conversationId) {
                var messageList = document.getElementById('message-list');
                messageList.innerHTML = '';

                var data = getTableData();
                var tablesByName = {};

                if (data && typeof data === 'object') {
                    for (var sheetId in data) {
                        if (Object.prototype.hasOwnProperty.call(data, sheetId) && data[sheetId] && data[sheetId].name) {
                            tablesByName[data[sheetId].name] = {
                                headers: data[sheetId].content[0] || [],
                                rows: data[sheetId].content.slice(1)
                            };
                        }
                    }
                }

                const messageTable = tablesByName["消息记录表"];
                if (!messageTable || !messageTable.rows.length) {
                    messageList.innerHTML = '<div style="text-align: center; color: var(--phone-secondary); padding: 40px;">Chưa có tin nhắn</div>';
                    return;
                }

                const headers = messageTable.headers;
                const sessionIdIndex = headers.indexOf("会话ID");
                const senderIndex = headers.indexOf("发送者");
                const contentIndex = headers.indexOf("消息内容");
                const timeIndex = headers.indexOf("消息发送时间");
                const imageDescIndex = headers.indexOf("图片描述");
                const videoDescIndex = headers.indexOf("视频描述");
                const replyOptions = ["主角回复选项1", "主角回复选项2", "主角回复选项3"];
                const opponentReplyKeys = ["对方回复1", "对方回复2", "对方回复3"];

                const messages = messageTable.rows.filter(row => row[sessionIdIndex] === conversationId);

                messages.forEach((row, messageIndex) => {
                    var isSelf = row[senderIndex] === '主角';
                    var senderName = row[senderIndex] || '';

                    var messageItem = document.createElement('div');
                    messageItem.className = 'message-item ' + (isSelf ? 'self' : 'other');

                    if (!isSelf) {
                        var avatar = document.createElement('div');
                        avatar.className = 'name-avatar';
                        avatar.style.width = '36px';
                        avatar.style.height = '36px';
                        avatar.textContent = senderName.substring(0, 4);
                        avatar.style.backgroundColor = generateColor(senderName);
                        messageItem.appendChild(avatar);
                    } else {
                        var avatar = document.createElement('div');
                        avatar.className = 'name-avatar';
                        avatar.style.width = '36px';
                        avatar.style.height = '36px';
                        avatar.textContent = 'Ta';
                        avatar.style.backgroundColor = '#4A90E2';
                        avatar.style.color = 'white';
                        avatar.style.fontWeight = 'bold';
                        messageItem.appendChild(avatar);
                    }

                    var bubbleWrapper = document.createElement('div');
                    bubbleWrapper.className = 'message-bubble-wrapper';
                    var bubble = document.createElement('div');
                    bubble.className = 'message-bubble';
                    bubble.textContent = row[contentIndex] || '';
                    bubbleWrapper.appendChild(bubble);
                    messageItem.appendChild(bubbleWrapper);
                    messageList.appendChild(messageItem);

                    var imageDesc = row[imageDescIndex];
                    var videoDesc = row[videoDescIndex];
                    if (imageDesc || videoDesc) {
                        var mediaItemDiv = document.createElement('div');
                        mediaItemDiv.className = 'message-item ' + (isSelf ? 'self' : 'other');
                        if (!isSelf) {
                            var placeholder = document.createElement('div');
                            placeholder.style.width = '44px';
                            placeholder.style.flexShrink = '0';
                            mediaItemDiv.appendChild(placeholder);
                        }
                        var mediaBubble = document.createElement('div');
                        mediaBubble.className = 'message-bubble moment-media-item';
                        mediaBubble.style.marginTop = '-10px';
                        mediaBubble.dataset.description = imageDesc || videoDesc;
                        var icon = imageDesc ? 'fa-image' : 'fa-video';
                        var text = imageDesc ? 'Nhấn để xem ảnh' : 'Nhấn để xem video';
                        mediaBubble.innerHTML = `<i class="fas ${icon}"></i> <span>${text}</span>`;
                        mediaBubble.onclick = () => openMediaViewer(mediaBubble.dataset.description);
                        mediaItemDiv.appendChild(mediaBubble);
                        messageList.appendChild(mediaItemDiv);
                    }

                    if (!isSelf) {
                        const choiceIdentifier = conversationId + '_' + messageIndex;
                        const hasOptions = replyOptions.some(option => row[headers.indexOf(option)]);

                        if (hasOptions) {
                            if (userChoices[choiceIdentifier] !== undefined) {
                                // A choice has been made, render the result directly
                                const chosenOptionIndex = userChoices[choiceIdentifier];
                                const optionText = row[headers.indexOf(replyOptions[chosenOptionIndex])];
                                const replyText = row[headers.indexOf(opponentReplyKeys[chosenOptionIndex])];

                                // Render protagonist's message
                                if (optionText) {
                                    var protagonistReply = document.createElement('div');
                                    protagonistReply.className = 'message-item self';
                                    protagonistReply.innerHTML = `
                                        <div class="name-avatar" style="width: 36px; height: 36px; background-color: #4A90E2; color: white; font-weight: bold;">Ta</div>
                                        <div class="message-bubble-wrapper">
                                            <div class="message-bubble">${optionText}</div>
                                            <div class="message-time">${formatTime(new Date())}</div>
                                        </div>
                                    `;
                                    messageList.appendChild(protagonistReply);
                                }

                                // Render opponent's reply if it exists
                                if (replyText) {
                                    var opponentReplyMessage = document.createElement('div');
                                    opponentReplyMessage.className = 'message-item other';
                                    opponentReplyMessage.innerHTML = `
                                        <div class="name-avatar" style="width: 36px; height: 36px; background-color: ${generateColor(senderName)};">${senderName.substring(0, 4)}</div>
                                        <div class="message-bubble-wrapper">
