            // Utility function to generate a consistent color based on a string
            function generateColor(str) {
                let hash = 0;
                if (str.length === 0) return '#888';
                for (let i = 0; i < str.length; i++) {
                    hash = str.charCodeAt(i) + ((hash << 5) - hash);
                    hash = hash & hash; // Convert to 32bit integer
                }
                let color = '#';
                for (let i = 0; i < 3; i++) {
                    let value = (hash >> (i * 8)) & 0xFF;
                    // Make colors brighter and less gray
                    value = (value & 0x7F) + 0x80; 
                    color += ('00' + value.toString(16)).substr(-2);
                }
                return color;
            }

            function formatTime(timeStr) {
                if (!timeStr) return '';
                var date = new Date(timeStr);
                if (isNaN(date.getTime())) {
                    // If parsing fails, it might be already formatted or an invalid string
                    return timeStr;
                }
                var hours = date.getHours().toString().padStart(2, '0');
                var minutes = date.getMinutes().toString().padStart(2, '0');
                return `${hours}:${minutes}`;
            }

