                            const storedIdentifier = localStorage.getItem('currentGameIdentifier');

                            // 如果本地没有存储标识符（首次），或者存储的与当前不符（新游戏），则重置
                            if (!storedIdentifier || storedIdentifier !== gameIdentifier) {
                                console.log('Phát hiện trò chơi mới hoặc lần tải đầu tiên, đang xóa tiến độ đã lưu...');
                                localStorage.removeItem('userChoices');
                                localStorage.removeItem('userLikes');
                                localStorage.removeItem('unreadConversations');
                                localStorage.removeItem('lastMessageHashes');
                                localStorage.setItem('phoneNotificationSeen', 'true');

                                // 清除后，立即用新的标识符更新本地存储
                                localStorage.setItem('currentGameIdentifier', gameIdentifier);

                                // 由于进度已被清除，需要重新加载用户选择等变量
                                userChoices = {};
                                userLikes = {};
                                unreadConversations = {};
                                lastMessageHashes = {};
                            }
                        }
                    } catch (e) {
                        console.error('Xảy ra lỗi trong quá trình phát hiện trò chơi mới:', e);
                    }
                    // --- 结束：新逻辑 ---

                    // ---- 基于最新消息内容比对的未读逻辑 ----
                    const data = getTableData();
                    const newHashes = {};
                    let hasNewMessages = false;

                    if (data) {
                        for (const sheetId in data) {
                            if (data.hasOwnProperty(sheetId) && data[sheetId].name === "消息记录表") {
                                const messageTable = data[sheetId].content;
                                const headers = messageTable[0] || [];
                                const sessionIdIndex = headers.indexOf("会话ID");
                                const contentIndex = headers.indexOf("消息内容");
                                const timeIndex = headers.indexOf("消息发送时间");

                                if (sessionIdIndex !== -1 && contentIndex !== -1 && timeIndex !== -1) {
                                    const conversations = {};
                                    // 找到每个会话的最新一条消息
                                    messageTable.slice(1).forEach(row => {
                                        const id = row[sessionIdIndex];
                                        const time = new Date(row[timeIndex]).getTime();
                                        if (!conversations[id] || time > conversations[id].time) {
                                            conversations[id] = { content: row[contentIndex], time: time };
                                        }
                                    });

                                    // 比对并标记未读
                                    for (const conversationId in conversations) {
                                        const latestMessage = conversations[conversationId].content;
                                        const newHash = simpleHash(latestMessage);
                                        newHashes[conversationId] = newHash;

                                        if (lastMessageHashes[conversationId] !== newHash) {
                                            unreadConversations[conversationId] = true;
                                            hasNewMessages = true;
                                        }
                                    }
                                }
                                break;
                            }
                        }
                    }

                    if (hasNewMessages) {
                        // 只有在检测到确实有新消息时，才更新未读状态和全局通知红点
                        localStorage.setItem('unreadConversations', JSON.stringify(unreadConversations));
                        localStorage.setItem('phoneNotificationSeen', 'false');
                        updatePhoneNotificationDot();
                    }

                    // 总是更新哈希记录以备下次比对
                    localStorage.setItem('lastMessageHashes', JSON.stringify(newHashes));
                    lastMessageHashes = newHashes;

                    if (document.getElementById('phone-page').style.display !== 'none') {
                        loadPhoneData(); // 仅更新手机内容
                    }
                });
            }

            // 为新插件端口注册回调（仅更新时间）
            if (newDataSourceAPI && typeof newDataSourceAPI.registerTableUpdateCallback === 'function') {
                newDataSourceAPI.registerTableUpdateCallback(function(newData) {
                    console.log('Interface received data update from NEW source for time, updating...');
                    updateTimeFromNewSource();
                });
            }
        });
