        .map-controls { position: absolute; right: 10px; top: 10px; z-index: 10; display: flex; flex-direction: column; gap: 5px; }
        .map-control-btn { background: var(--bg-container); border: 1px solid var(--border-color); color: var(--text-title); border-radius: 50%; cursor: pointer; width: 36px; height: 36px; line-height: 34px; text-align: center; font-size: 1rem; box-shadow: 0 1px 3px var(--shadow-color); }
        #visual-map { display: block; width: 100%; height: 100%; cursor: grab; }
        #visual-map:active { cursor: grabbing; }
        .map-location-group { cursor: pointer; transition: all 0.2s ease; }
        .map-location-rect { fill: rgba(140, 110, 84, 0.3); stroke: var(--accent-color1); stroke-width: 1.5px; }
        .map-location-group:hover .map-location-rect { fill: rgba(180, 138, 92, 0.6); }
        .map-location-label { fill: var(--text-title); text-anchor: middle; dominant-baseline: middle; pointer-events: none; user-select: none; font-size: 16px; font-weight: bold; font-family: var(--font-title); }

        .protagonist-map-avatar {
            pointer-events: none;
        }
        .protagonist-map-avatar .pulse-wave {
            fill: none;
            stroke: var(--accent-color2);
            stroke-width: 2px;
            transform-box: fill-box;
            transform-origin: center;
            animation: pulse-wave-animation 2s infinite cubic-bezier(0.445, 0.05, 0.55, 0.95);
        }

        @keyframes pulse-wave-animation {
            0% {
                transform: scale(1);
                opacity: 1;
            }
            100% {
                transform: scale(2.5);
                opacity: 0;
            }
        }

        .horizontal-scroll-list {
            display: flex;
            flex-wrap: nowrap;
            gap: 12px; /* 增加按钮间距 */
            overflow-x: auto;
            padding: 5px 0 15px 0; /* 调整内边距 */
            align-items: center;
        }
        .horizontal-scroll-list::-webkit-scrollbar { height: 6px; } /* 加粗滚动条 */
        .horizontal-scroll-list::-webkit-scrollbar-track { background: rgba(0,0,0,0.1); }
        .horizontal-scroll-list::-webkit-scrollbar-thumb { background: var(--accent-color1); border-radius: 2px; }

        /* 移除所有宽屏样式 */

    @media (max-width: 768px) {
        :root { --font-size-base: 12px; --spacing-md: 10px; --spacing-lg: 15px; }
        body { padding: 5px; }
        .map-interface { padding: var(--spacing-lg) var(--spacing-md); }
        .map-header { flex-direction: column; gap: var(--spacing-md); }
        .map-header h2 { font-size: 1.5rem; }
        .top-right-buttons { order: -1; width: 100%; justify-content: center; gap: 8px; flex-wrap: wrap; margin-bottom: 10px; }
        .top-right-buttons .partner-button { flex-grow: 1; justify-content: center; }
        #visual-map-container { height: 38vh; min-height: 220px; }
        .partner-button-list, .external-area-buttons { display: flex; flex-wrap: nowrap; overflow-x: auto; padding-bottom: 10px; -webkit-overflow-scrolling: touch; scrollbar-width: none; flex-shrink: 0; white-space: nowrap; }
        .partner-button-list::-webkit-scrollbar, .external-area-buttons::-webkit-scrollbar { display: none; }
        .partner-button { padding: 8px 14px; font-size: 0.9rem; flex-shrink: 0; white-space: nowrap; }
        #important-character-buttons .partner-button { padding: 5px 10px 5px 5px; }
        .sub-location-grid { grid-template-columns: 1fr; }
        .modal-dialog { width: 95vw; padding: var(--spacing-lg) 15px; }
        .modal-dialog h4 { font-size: 1.3rem; }
        #modal-character-name { font-size: 1.7rem; }
        .attributes-grid { grid-template-columns: repeat(2, 1fr); gap: var(--spacing-sm); }
        .attribute-item { padding: var(--spacing-xs); }
        .interaction-options-grid { grid-template-columns: 1fr; gap: var(--spacing-sm); }
        .interaction-button, .sub-location-button { padding: 10px; font-size: 0.95rem; }
        .shop-item, .inventory-item, .skill-item { flex-direction: column; align-items: center; gap: 10px; }
        .shop-item > div, .inventory-item > div, .skill-item > div { text-align: center; }
        .use-button { width: auto; padding-left: 40px; padding-right: 40px; }
    }

    @media (max-width: 480px) {
        #protagonist-status-bar {
            flex-wrap: wrap; /* 允许换行 */
            gap: 10px;
            justify-content: center; /* 居中头像等元素 */
        }

        .protagonist-portrait {
            width: 60px; /* 进一步缩小头像 */
            height: 60px;
        }

        .protagonist-stats-container {
            padding-left: 0;
            border-left: none; /* 移除分割线 */
            width: 100%; /* 占满可用空间以帮助居中 */
            min-height: 116px; /* 为原始尺寸的六边形提供足够垂直空间 */
            justify-content: center; /* 水平居中 */
            align-items: center; /* 垂直居中 */
        }

        .stats-hexagon {
            transform: scale(0.8); /* 缩小整个六边形（包括标签和画布） */
            transform-origin: center center;
        }

        .protagonist-core-info {
            flex-direction: column; /* 改为垂直排列 */
            align-items: stretch; /* 拉伸以填充宽度 */
            gap: 12px;
            width: 100%; /* 占满整行宽度 */
        }

        .protagonist-text-info {
            align-items: center; /* 居中对齐文本 */
            text-align: center;
            width: 100%;
        }
        .protagonist-name-info, #protagonist-name {
                align-items: center; /* 确保名字也居中 */
        }
        #protagonist-name {
            font-size: 1.3rem; /* 调整名字大小 */
        }

        .protagonist-main-controls {
            order: -1; /* 将按钮提到最前面 */
            justify-content: center; /* 居中按钮 */
            width: 100%;
        }
    }
    </style>
</head>
<body>
    <div class="map-interface">
        <header class="top-bar">
            <div class="title-container">
                <h1 id="map-title">Đang tải tiêu đề bản đồ...</h1>
                <div id="current-time-container" class="current-time-container">
                    <i class="fas fa-clock"></i>
                    <span id="current-time">----</span>
                </div>
            </div>
        </header>

        <section id="protagonist-status-bar">
            <div id="protagonist-portrait-container" class="protagonist-portrait" title="Nhấn để tải lên ảnh đại diện tùy chỉnh">
                <img id="protagonist-portrait-img" src="" alt="Ảnh đại diện nhân vật chính">
                <div class="portrait-upload-prompt">Thay đổi ảnh đại diện</div>
            </div>
            <div class="protagonist-core-info">
                <div class="protagonist-text-info">
                    <div class="protagonist-name-info">
                        <div style="display: flex; align-items: center; gap: 10px;">
                            <h2 id="protagonist-name" style="margin: 0;"></h2>
                            <div id="protagonist-douqi-level" class="protagonist-douqi-level"></div>
                        </div>
                        <div id="protagonist-details" class="protagonist-details"></div>
                    </div>
                    <div id="protagonist-money" class="protagonist-money"></div>
                </div>
                <div class="protagonist-main-controls">
                    <div class="function-btn" id="skill-button"><i class="fas fa-magic"></i><span>Kỹ năng</span></div>
                    <div class="function-btn" id="inventory-button"><i class="fas fa-box-open"></i><span>Túi đồ</span></div>
                    <div class="function-btn" id="quest-button"><i class="fas fa-scroll"></i><span>Nhiệm vụ</span></div>
                </div>
            </div>
            <div class="protagonist-stats-container">
                <div class="stats-hexagon">
                   <div class="hexagon-shape"></div>
                   <canvas id="main-stats-radar" width="100" height="115.5"></canvas>
                </div>
            </div>
        </section>


        <section id="key-characters-section">
            <div class="section-title"><i class="fas fa-users"></i>Nhân vật quan trọng</div>
            <div id="character-bar" class="horizontal-scroll-list">
                </div>
        </section>

        <main class="content-grid" style="margin-top: 20px;">
            <section id="visual-map-container">
                <div class="map-controls">
                    <button id="zoom-in-btn" class="map-control-btn"><i class="fas fa-plus"></i></button>
                    <button id="zoom-out-btn" class="map-control-btn"><i class="fas fa-minus"></i></button>
                </div>
                <svg id="visual-map" preserveAspectRatio="xMidYMid meet" xmlns="http://www.w3.org/2000/svg"></svg>
            </section>

            <section id="external-areas-section" class="grid-item" style="grid-column: 1 / -1;">
                <div class="section-title"><i class="fas fa-globe-americas"></i>Khu vực bên ngoài</div>
                <div id="external-areas-list" class="horizontal-scroll-list"></div>
            </section>

        </main>
    </div>

    <div id="character-modal" class="modal-overlay"><div class="modal-dialog"><button class="close-modal-button">&times;</button><h4 id="modal-character-name"></h4><div id="modal-character-content" class="modal-content"></div><div id="modal-character-interactions" class="interaction-grid"></div></div></div>
    <div id="map-element-modal" class="modal-overlay"><div class="modal-dialog"><button class="close-modal-button">&times;</button><h4 id="modal-element-name"></h4><div id="modal-element-description" class="modal-content"></div><div id="modal-element-interactions" class="interaction-grid"></div></div></div>
    <div id="skill-modal" class="modal-overlay"><div class="modal-dialog"><button class="close-modal-button">&times;</button><h4><i class="fas fa-magic"></i> Danh sách Kỹ năng</h4><div id="skill-items-container" class="modal-content"></div></div></div>
    <div id="inventory-modal" class="modal-overlay"><div class="modal-dialog"><button class="close-modal-button">&times;</button><h4><i class="fas fa-box-open"></i> Túi đồ</h4><div id="inventory-items-container" class="modal-content"></div></div></div>
    <div id="quest-modal" class="modal-overlay"><div class="modal-dialog"><button class="close-modal-button">&times;</button><h4><i class="fas fa-scroll"></i> Nhật ký Nhiệm vụ</h4><div id="quest-items-container" class="modal-content"></div></div></div>
    <div id="shop-modal" class="modal-overlay"><div class="modal-dialog"><button class="close-modal-button">&times;</button><h4><i class="fas fa-store"></i> Cửa hàng</h4><div id="shop-items-container" class="modal-content"></div></div></div>

    <script>
        document.addEventListener('DOMContentLoaded', function() {
            // Use live data source from parent, or a fallback that returns nothing.
            const dataSourceAPI = (typeof parent !== 'undefined' && parent.AutoCardUpdaterAPI) ? parent.AutoCardUpdaterAPI : {
                exportTableAsJson: function() {
                    console.log("No data source found.");
                    return {}; // Return empty object if no source
                },
                registerTableUpdateCallback: function(callback) {
                    console.log("No data source found to register callback.");
                }
            };

            function getTableData() {
                try {
                    return dataSourceAPI.exportTableAsJson();
                } catch (e) {
                    console.error("Error getting table data:", e);
                    return {};
                }
            }

            function processJsonData(json) {
                const tables = {};
                if (!json || typeof json !== 'object') {
                    console.error("Invalid JSON data provided.");
                    return null;
                }
                for (const sheetId in json) {
                    if (Object.prototype.hasOwnProperty.call(json, sheetId) && json[sheetId] && json[sheetId].name) {
                        const sheet = json[sheetId];
                        tables[sheet.name] = {
                            headers: sheet.content[0] || [],
                            rows: sheet.content.slice(1)
                        };
                    }
                }
                return tables;
            }

            function renderUI(tables) {
                if (!tables) return;

                // --- 1. 渲染全局数据 ---
                const globalTable = tables["全局数据表"];
                const globalData = globalTable?.rows[0] || [];
                const globalHeaders = globalTable?.headers || [];

                document.getElementById('map-title').textContent = globalData[globalHeaders.indexOf("地图标题")] || 'Khu vực không xác định';
                document.getElementById('current-time').textContent = `Thời gian hiện tại: ${globalData[globalHeaders.indexOf("当前时间")] || '----'}`;

                // --- 2. 渲染主角状态栏 ---
                const pInfoTable = tables["主角信息"];
                const pStatusTable = tables["主角状态"];
                const pInfoHeaders = pInfoTable?.headers || [];
                const pStatusHeaders = pStatusTable?.headers || [];
                const pInfo = pInfoTable?.rows[0] || [];
                const pStatus = pStatusTable?.rows[0] || [];

                // 总是尝试加载头像
                const charactersTable = tables["重要人物表"];
                let protagonistAvatarUrl = '';
                if (pInfo.length > 0) {
                    const protagonistName = pInfo[pInfoHeaders.indexOf("人物名称")];
                    if (charactersTable && charactersTable.rows) {
                        const protagonistEntry = charactersTable.rows.find(row => row[charactersTable.headers.indexOf('姓名')] === protagonistName);
                        if (protagonistEntry) {
                            protagonistAvatarUrl = protagonistEntry[charactersTable.headers.indexOf('头像')] || '';
                        }
                    }
                }
                loadProtagonistAvatar(protagonistAvatarUrl, '主角');

                if (pInfo.length > 0) {
                    // 基本信息
                    document.getElementById('protagonist-name').textContent = pInfo[pInfoHeaders.indexOf("人物名称")] || 'Nhân vật chính';
                    const detailsContainer = document.getElementById('protagonist-details');
                    detailsContainer.innerHTML = `
                        <div class="detail-item">${pInfo[pInfoHeaders.indexOf("性别/年龄")] || 'Chưa rõ'}</div>
                        <div class="detail-item">${pInfo[pInfoHeaders.indexOf("职业/身份")] || 'Chưa rõ'}</div>
                    `;
                    document.getElementById('protagonist-money').textContent = `Tiền Vàng: ${pStatus[pStatusHeaders.indexOf("拥有金钱")] || '0'}`;

                    // 斗气等级显示
                    const douqiLevel = pStatus[pStatusHeaders.indexOf("斗气等级")] || "Đấu Khí nhất đoạn";
                    document.getElementById('protagonist-douqi-level').textContent = douqiLevel;

                    // 属性雷达图
                    const statsString = pStatus[pStatusHeaders.indexOf("当前属性")] || "";
                    const stats = Object.fromEntries(
                        statsString.split(/[,，\/]/)
                            .map(s => s.split(/[:：]/))
                            .map(([k, v]) => [k.trim(), parseInt(v) || 0])
                            .filter(([k, v]) => k)
                    );
                    drawRadarChart(stats, 'main-stats-radar');

                    // "详细信息"按钮已移除，无需绑定
                }

                // --- 3. 渲染重要人物按钮 (包括主角) ---
                const characterBar = document.getElementById('character-bar');
                characterBar.innerHTML = '';

                // 首先添加主角按钮
                if (pInfo.length > 0) {
                     const pBtn = document.createElement('button');
                     pBtn.className = 'function-btn';
                     pBtn.innerHTML = `<i class="fas fa-user-circle"></i> ${pInfo[pInfoHeaders.indexOf("人物名称")] || 'Nhân vật chính'}`;
                     pBtn.onclick = () => openCharacterModal({
                         isProtagonist: true,
                         info: pInfo, infoHeaders: pInfoHeaders,
                         status: pStatus, statusHeaders: pStatusHeaders
                     });
                     characterBar.appendChild(pBtn);
                }

                const characters = tables["重要人物表"]?.rows || [];
                const charHeaders = tables["重要人物表"]?.headers || [];
                const protagonistName = pInfo[pInfoHeaders.indexOf("人物名称")];
                characters.forEach(charData => {
                    const charName = charData[charHeaders.indexOf('姓名')];
                    // 过滤掉主角本人，因为已在上面独立添加
                    if (charName && charName !== protagonistName) {
                        const isDeparted = charData[charHeaders.indexOf('是否离场')] === '是';
                        const charBtn = document.createElement('button');
                        charBtn.className = 'function-btn';
                        charBtn.innerHTML = `<i class="fas fa-id-badge"></i> ${charName}`;
                        charBtn.onclick = () => openCharacterModal({ info: charData, infoHeaders: charHeaders });
                        if (isDeparted) {
                            charBtn.style.display = 'none';
                        }
                        characterBar.appendChild(charBtn);
                    }
                });

                // --- 4. 设置弹窗内容 ---
                setupModalContent('skill-modal', 'skill-items-container', tables["主角技能表"], (item, headers) => {
                    const listItem = document.createElement('li');
                    listItem.className = 'list-item';

                    const content = document.createElement('div');
                    content.className = 'list-item-content';
                    const skillName = item[headers.indexOf('技能名称')];
                    content.innerHTML = `
                        <div class="item-name">${skillName} <small>[${item[headers.indexOf('等级/阶段')]}]</small></div>
                        <div class="item-details">${item[headers.indexOf('效果描述')]}</div>
                    `;

                    const useButton = document.createElement('button');
                    useButton.className = 'use-button';
                    useButton.textContent = 'Sử dụng';
                    useButton.onclick = () => sendGameActionRequest(`Sử dụng kỹ năng ${skillName}`);

                    listItem.appendChild(content);
                    listItem.appendChild(useButton);
                    return listItem;
                });
                setupModalContent('inventory-modal', 'inventory-items-container', tables["背包物品表"], (item, headers) => {
                    const listItem = document.createElement('li');
                    listItem.className = 'list-item';

                    const content = document.createElement('div');
                    content.className = 'list-item-content';
                    const itemName = item[headers.indexOf('物品名称')];
                    content.innerHTML = `
                        <div class="item-name">${itemName} (x${item[headers.indexOf('数量')]})</div>
                        <div class="item-details">${item[headers.indexOf('描述/效果')]}</div>
                    `;

                    const useButton = document.createElement('button');
                    useButton.className = 'use-button';
                    useButton.textContent = 'Sử dụng';
                    useButton.onclick = () => sendGameActionRequest(`Sử dụng vật phẩm ${itemName}`);

                    listItem.appendChild(content);
                    listItem.appendChild(useButton);
                    return listItem;
                });
                setupModalContent('quest-modal', 'quest-items-container', tables["任务与事件表"], (item, headers) => {
                    const listItem = document.createElement('li');
                    listItem.className = 'list-item';
                    listItem.innerHTML = `
                        <div class="quest-item">
                            <div class="item-name">${item[headers.indexOf('任务名称')]} <small>[${item[headers.indexOf('任务类型')]}]</small></div>
                            <div class="item-details"><b>Người giao:</b> ${item[headers.indexOf('发布者')]}</div>
                            <div class="item-details"><b>Mô tả:</b> ${item[headers.indexOf('详细描述')]}</div>
                            <div class="item-details"><b>Tiến độ:</b> ${item[headers.indexOf('当前进度')]}</div>
                        </div>
                    `;
                    return listItem;
                });

                // Render Map and External Areas
                const locations = [];
                const mainLocTable = tables["主要地点表"];
                const elementsTable = tables["地图元素表"];
                const elementsByLocation = {};

                if (elementsTable?.rows) {
                    elementsTable.rows.forEach(elRow => {
                        const locName = elRow[elementsTable.headers.indexOf('所属主地点')];
                        if (!locName) return;
                        if (!elementsByLocation[locName]) elementsByLocation[locName] = [];
                        elementsByLocation[locName].push({
                            name: elRow[elementsTable.headers.indexOf('元素名称')],
                            type: elRow[elementsTable.headers.indexOf('元素类型')],
                            description: elRow[elementsTable.headers.indexOf('元素描述')],
                            status: elRow[elementsTable.headers.indexOf('状态')],
                            interactions: [
                                elRow[elementsTable.headers.indexOf('互动选项1')],
                                elRow[elementsTable.headers.indexOf('互动选项2')],
                                elRow[elementsTable.headers.indexOf('互动选项3')]
                            ].filter(Boolean)
                        });
                    });
                }

                if (mainLocTable?.rows) {
                    mainLocTable.rows.forEach((locRow, index) => {
                        const name = locRow[mainLocTable.headers.indexOf('地点名称')];
                        if (!name) return;

                        let x = parseInt(locRow[mainLocTable.headers.indexOf('X坐标')]);
                        let y = parseInt(locRow[mainLocTable.headers.indexOf('Y坐标')]);
                        let width = parseInt(locRow[mainLocTable.headers.indexOf('宽度')]);
                        let height = parseInt(locRow[mainLocTable.headers.indexOf('高度')]);

                        // Fill missing parameters with defaults
                        if (isNaN(x)) x = 50 + (index % 4) * 180; // Default X, creates a grid-like start
                        if (isNaN(y)) y = 50 + Math.floor(index / 4) * 120; // Default Y
                        if (isNaN(width)) width = 150; // Default width
                        if (isNaN(height)) height = 80; // Default height

                        locations.push({
                            name, x, y, width, height,
                            description: locRow[mainLocTable.headers.indexOf('环境描述')],
                            elements: elementsByLocation[name] || []
                        });
                    });
                }

                // 传入主角当前位置
                const protagonistLocation = pStatus[pStatusHeaders.indexOf("当前所在主地点")];
                renderMap(locations, protagonistLocation);

                const externalAreas = (globalData[globalHeaders.indexOf("外部区域列表")] || '').split(/[,，；;]/).map(s => s.trim()).filter(Boolean);
                renderExternalAreas(externalAreas);
            }

            /**
             * 当图片加载失败时，应用一个备用UI（彩色背景加问号）。
             * @param {HTMLElement} element - 图片的容器元素。
             */
            function applyImageFallback(element) {
                if (!element) return;
                const colors = ['#5a5a5a', '#6a4c4c', '#4c6a4c', '#4c4c6a', '#6a6a4c', '#4c6a6a'];
                const randomColor = colors[Math.floor(Math.random() * colors.length)];

                element.innerHTML = ''; // 清除损坏的img标签
                element.style.backgroundImage = 'none';
                element.style.backgroundColor = randomColor;
                element.style.display = 'flex';
                element.style.justifyContent = 'center';
                element.style.alignItems = 'center';
                element.style.color = '#fff';
                const size = Math.min(element.offsetWidth, element.offsetHeight);
                element.style.fontSize = `${size * 0.6}px`;
                element.style.fontWeight = 'bold';
                element.style.lineHeight = '1';
                element.textContent = '?';
            }

            /**
             * 从多个来源加载主角头像，并提供强大的回退机制。
             * @param {string} avatarUrlFromData - 从数据源获取的头像URL。
             * @param {string} protagonistName - 主角名字，用于localStorage的键。
             */
            function loadProtagonistAvatar(avatarUrlFromData, protagonistName) {
                const container = document.getElementById('protagonist-portrait-container');
                const imgElement = document.getElementById('protagonist-portrait-img');
                const customAvatarKey = 'protagonist-custom-avatar-主角';
                const customAvatar = localStorage.getItem(customAvatarKey);
                const defaultAvatar = "data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 100 100'%3E%3Ctext y='.9em' font-size='90'%3E👤%3C/text%3E%3C/svg%3E";

                // 清理旧的UI元素（如图标和重置按钮）
                const existingResetBtn = container.querySelector('.avatar-reset-btn');
                if (existingResetBtn) existingResetBtn.remove();

                // 确保图片和容器恢复正常样式
                imgElement.style.display = 'block';
                container.style.backgroundColor = '#e0d5c8';
                // 如果容器里有文字（比如fallback的问号），先清空
                if(container.textContent) container.textContent = '';
                // 确保图片元素在容器里
                if(!container.contains(imgElement)) container.appendChild(imgElement);



                const sources = [];
                if (customAvatar) sources.push(customAvatar);
                if (avatarUrlFromData && (avatarUrlFromData.startsWith('http') || avatarUrlFromData.startsWith('data:'))) {
                    sources.push(avatarUrlFromData);
                }
                sources.push(defaultAvatar);

                let sourceIndex = 0;
                const tryNextSource = () => {
                    if (sourceIndex >= sources.length) {
                        applyImageFallback(container);
                        return;
                    }
                    imgElement.src = sources[sourceIndex];
                    sourceIndex++;
                };

                imgElement.onerror = tryNextSource;
                tryNextSource();
            }

            document.getElementById('protagonist-portrait-container').addEventListener('click', () => {
                const customAvatarKey = 'protagonist-custom-avatar-主角';

