            });

            function drawRadarChart(stats, canvasId) {
                const canvas = document.getElementById(canvasId);
                if (!canvas || !canvas.getContext) return;

                const ctx = canvas.getContext('2d');
                const width = canvas.width;
                const height = canvas.height;
                const centerX = width / 2;
                const centerY = height / 2;
                const radius = width / 2 - 20; // 留出标签空间

                const labels = ["Sức mạnh", "Nhanh nhẹn", "Thể chất", "Trí tuệ", "Cảm giác", "Sức hút"];
                const displayLabels = ["Lực", "Mẫn", "Thể", "Tuệ", "Tri", "Mị"];
                // 确保即使数据不全，也按固定顺序和数量渲染
                const values = labels.map(label => stats[label] || 0);
                const numStats = labels.length;
                if (numStats === 0) return;

                ctx.clearRect(0, 0, width, height);

                // Draw radar shape
                ctx.beginPath();
                for (let i = 0; i < numStats; i++) {
                    const angle = (Math.PI * 2 / numStats) * i - Math.PI / 2;
                    const value = Math.max(0, Math.min(30, values[i])) / 30; // Normalize to 0-1, max value 30 for scale
                    const x = centerX + radius * value * Math.cos(angle);
                    const y = centerY + radius * value * Math.sin(angle);
                    if (i === 0) {
                        ctx.moveTo(x, y);
                    } else {
                        ctx.lineTo(x, y);
                    }
                }
                ctx.closePath();
                ctx.fillStyle = 'rgba(180, 138, 92, 0.5)';
                ctx.fill();
                ctx.strokeStyle = 'rgba(62, 39, 26, 0.8)';
                ctx.stroke();

                // Draw labels
                const labelContainer = canvas.parentElement;
                // Clear previous labels
                labelContainer.querySelectorAll('.stat-label').forEach(el => el.remove());

                labels.forEach((label, i) => {
                    const angle = (Math.PI * 2 / numStats) * i - Math.PI / 2;
                    const labelRadius = radius + 10;
                    const x = centerX + labelRadius * Math.cos(angle);
                    const y = centerY + labelRadius * Math.sin(angle);

                    const labelEl = document.createElement('div');
                    labelEl.className = 'stat-label';
                    labelEl.textContent = displayLabels[i];
                    labelEl.style.left = `${x}px`;
                    labelEl.style.top = `${y}px`;
                    labelContainer.appendChild(labelEl);
                });
            }

            function openModal(modalId) { document.getElementById(modalId).classList.add('visible'); }
            function closeModal(modalId) { document.getElementById(modalId).classList.remove('visible'); }

            /**
             * 检查两个矩形是否重叠（带边距）。
             * @param {object} rect1 - {x, y, width, height}
             * @param {object} rect2 - {x, y, width, height}
             * @returns {boolean} - 如果重叠则返回 true。
             */
            function checkOverlap(rect1, rect2) {
                var margin = 10; // 增加边距防止标签接触
                return (rect1.x < rect2.x + rect2.width + margin &&
                        rect1.x + rect1.width + margin > rect2.x &&
                        rect1.y < rect2.y + rect2.height + margin &&
                        rect1.y + rect1.height + margin > rect2.y);
            }

            /**
             * 使用简单的力导向算法调整布局，以最小化重叠。
             * @param {Array<object>} locations - 地点对象数组。
             * @returns {Array<object>} - 修改后的地点对象数组。
             */
            function adjustLayoutForOverlaps(locations) {
                if (!locations || locations.length < 2) return locations;
                var iterations = 150, forceFactor = 0.5;
                for (var i = 0; i < iterations; i++) {
                    for (var j = 0; j < locations.length; j++) {
                        for (var k = j + 1; k < locations.length; k++) {
                            var locA = locations[j], locB = locations[k];
                            if (checkOverlap(locA, locB)) {
                                var dx = (locA.x + locA.width / 2) - (locB.x + locB.width / 2);
                                var dy = (locA.y + locA.height / 2) - (locB.y + locB.height / 2);
                                var distance = Math.sqrt(dx * dx + dy * dy);
                                if (distance === 0) { // 防止除零
                                    dx = (Math.random() - 0.5) * 0.1;
                                    dy = (Math.random() - 0.5) * 0.1;
                                    distance = Math.sqrt(dx * dx + dy * dy);
                                }
                                var overlapX = (locA.width / 2 + locB.width / 2) - Math.abs(dx);
                                var overlapY = (locA.height / 2 + locB.height / 2) - Math.abs(dy);
                                if (overlapX > 0 && overlapY > 0) {
                                    var moveX = (dx / distance) * overlapX * forceFactor;
                                    var moveY = (dy / distance) * overlapY * forceFactor;
                                    locA.x += moveX; locA.y += moveY;
                                    locB.x -= moveX; locB.y -= moveY;
                                }
                            }
                        }
                    }
                }
                return locations;
            }

            function renderMap(locations, protagonistLocation) {
                // 在渲染前调整布局以避免重叠
                if (locations && locations.length > 0) {
                    locations = adjustLayoutForOverlaps(locations);
                }
                const svg = document.getElementById('visual-map');
                svg.innerHTML = '';
                if (!locations || locations.length === 0) {
                    svg.setAttribute('viewBox', '0 0 800 600');
                    const text = document.createElementNS("http://www.w3.org/2000/svg", 'text');
                    text.setAttribute('x', '400');
                    text.setAttribute('y', '300');
                    text.setAttribute('class', 'map-location-label');
                    text.textContent = 'Chưa có dữ liệu bản đồ';
                    svg.appendChild(text);
                    return;
                }

                let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
                locations.forEach(l => {
                    minX = Math.min(minX, l.x);
                    minY = Math.min(minY, l.y);
                    maxX = Math.max(maxX, l.x + l.width);
                    maxY = Math.max(maxY, l.y + l.height);
                });

                const padding = Math.max((maxX - minX) * 0.1, (maxY - minY) * 0.1, 50);
                const vbX = minX - padding, vbY = minY - padding;
                const vbW = (maxX - minX) + (padding * 2);
                const vbH = (maxY - minY) + (padding * 2);
                svg.setAttribute('viewBox', `${vbX} ${vbY} ${vbW} ${vbH}`);

                locations.forEach(loc => {
                    const g = document.createElementNS("http://www.w3.org/2000/svg", 'g');
                    g.setAttribute('class', 'map-location-group');
                    g.addEventListener('click', () => openLocationModal(loc));

                    const r = document.createElementNS("http://www.w3.org/2000/svg", 'rect');
                    r.setAttribute('x', loc.x);
                    r.setAttribute('y', loc.y);
                    r.setAttribute('width', loc.width);
                    r.setAttribute('height', loc.height);
                    r.setAttribute('class', 'map-location-rect');
                    r.setAttribute('rx', '8'); // Rounded corners to match theme

                    const t = document.createElementNS("http://www.w3.org/2000/svg", 'text');
                    t.setAttribute('x', loc.x + loc.width / 2);
                    t.setAttribute('y', loc.y + loc.height / 2);
                    t.setAttribute('class', 'map-location-label');
                    t.textContent = loc.name;

                    g.appendChild(r);
                    g.appendChild(t);
                    svg.appendChild(g);

                    // 如果是主角所在位置，添加头像标记
                    if (loc.name === protagonistLocation) {
                        const protagonistImgSrc = document.getElementById('protagonist-portrait-img').src;
                        const avatarGroup = document.createElementNS("http://www.w3.org/2000/svg", 'g');
                        avatarGroup.setAttribute('class', 'protagonist-map-avatar');

                        // 创建外围的脉冲波circle
                        const pulseCircle = document.createElementNS("http://www.w3.org/2000/svg", 'circle');
                        pulseCircle.setAttribute('cx', loc.x + loc.width / 2);
                        pulseCircle.setAttribute('cy', loc.y + loc.height / 2);
                        pulseCircle.setAttribute('r', '12'); // 初始半径
                        pulseCircle.setAttribute('class', 'pulse-wave');

                        // 创建用作头像的image元素
                        const avatarImage = document.createElementNS("http://www.w3.org/2000/svg", 'image');
                        avatarImage.setAttribute('x', loc.x + loc.width / 2 - 12);
                        avatarImage.setAttribute('y', loc.y + loc.height / 2 - 12);
                        avatarImage.setAttribute('width', '24');
                        avatarImage.setAttribute('height', '24');
                        avatarImage.setAttribute('href', protagonistImgSrc);

                        // 创建一个圆形剪裁蒙版
                        const clipPath = document.createElementNS('http://www.w3.org/2000/svg', 'clipPath');
                        const clipPathId = 'avatar-clip-path';
                        clipPath.setAttribute('id', clipPathId);
                        const clipCircle = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
                        clipCircle.setAttribute('cx', loc.x + loc.width / 2);
                        clipCircle.setAttribute('cy', loc.y + loc.height / 2);
                        clipCircle.setAttribute('r', '12');
                        clipPath.appendChild(clipCircle);

                        avatarImage.setAttribute('clip-path', `url(#${clipPathId})`);

                        avatarGroup.appendChild(clipPath);
                        avatarGroup.appendChild(pulseCircle);
                        avatarGroup.appendChild(avatarImage);
                        svg.appendChild(avatarGroup);
                    }
                });
            }

