                    const details = [{ label: 'Giới tính/Tuổi', value: pDetails["性别/年龄"] }, { label: 'Ngoại hình', value: pDetails["外貌特征"] }, { label: 'Nghề nghiệp/Thân phận', value: pDetails["职业/身份"] }, { label: 'Bối cảnh', value: pDetails["背景故事"] }, { label: 'Tính cách', value: pDetails["性格特点"] }, { label: 'Trạng thái', value: pDetails["当前状态"] }];
                    details.forEach(detail => {
