                        { label: 'Nghề nghiệp/Thân phận', value: character.info[character.infoHeaders.indexOf('职业/身份')] }, 
                        { label: 'Tính cách', value: character.info[character.infoHeaders.indexOf('性格特点')] }, 
                        { label: 'Bối cảnh', value: character.info[character.infoHeaders.indexOf('背景故事')] }, 
